import java.io.FileInputStream;
  import java.io.FileNotFoundException;
  import java.io.IOException;
  import java.util.Scanner;
  import java.util.regex.Matcher;
  import org.apache.log4j.Logger;
  import java.util.regex.Pattern;
  import sailpoint.api.Provisioner;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Identity;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Util;
  import sailpoint.api.ObjectUtil;
  import sailpoint.tools.Message;
  import java.text.SimpleDateFormat;
  import java.util.Locale;
  import java.util.concurrent.TimeUnit;
import sailpoint.object.Custom;
  
  
  public long getDifferenceInDays(String first){
 SimpleDateFormat sdf=new SimpleDateFormat("yyyy-MM-dd",Locale.ENGLISH);
  Calendar cal=Calendar.getInstance();
  
  Date firstDate=sdf.parse(first);
  Date secondDate=new Date();
  long timeDifferenceInMillis=firstDate.getTime()-secondDate.getTime();
  TimeUnit time=TimeUnit.DAYS;
 long differenceInDays=time.convert(timeDifferenceInMillis,TimeUnit.MILLISECONDS);
  java.util.Date date=new java.util.Date();
     return differenceInDays;
  }

  public void  updateIdentity(Map feedMap){
    Identity identity = null;
    Identity managerIdentity = null;
    Identity contractorManIdentity = null;
    try{
      if(feedMap!=null && !feedMap.isEmpty()){
        if(feedMap.get(pivotColumn)!=null){
          identity = context.getObjectByName(Identity.class, feedMap.get(pivotColumn) );
          if(identity!=null && ( !identity.isInactive() ||  Util.nullSafeCaseInsensitiveEq(config.get("updateInactive"),"true")  ) ){
            Identity idCube = ObjectUtil.lockIdentity(context, identity.getName());
            for(String attributeName : feedMap.keySet()){
              if(pivotColumn.equalsIgnoreCase(attributeName)){
                continue;
              }
              if(attributeName.equalsIgnoreCase(manager)){
                managerIdentity = context.getObjectByName(Identity.class, feedMap.get(attributeName) );
                if(managerIdentity!=null && !managerIdentity.isInactive()){
                  idCube.setManager(managerIdentity);
                  identitiesUpdated.add(identity.getName());
                }else{                  
                  errorListSet.add(feedMap.get(attributeName)+" = invalid manager");
                  identitiesNotUpdated.add(identity.getName());
                }
              }else if(attributeName.equalsIgnoreCase(contractorManager)){
                contractorManIdentity = context.getObjectByName(Identity.class, feedMap.get(attributeName));
                if(contractorManIdentity!=null && !contractorManIdentity.isInactive()){
                  idCube.setAttribute(attributeName,feedMap.get(attributeName));
                  identitiesUpdated.add(identity.getName());
                }else{
                  errorListSet.add(feedMap.get(attributeName)+" = invalid contractorManager");
                  identitiesNotUpdated.add(identity.getName());
                }
              }else{
                idCube.setAttribute(attributeName, feedMap.get(attributeName));
                identitiesUpdated.add(identity.getName());
              }
            }
            context.saveObject(idCube);
            ObjectUtil.unlockIdentity(context, idCube);
          }else{
            errorListSet.add(feedMap.get(pivotColumn)+" = invalid Identity");
            identitiesNotUpdated.add(feedMap.get(pivotColumn));
          }
        }
      }
    }catch(Exception e){
      taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
    }
  }


  public List delimToList(String delimiter,String lineString){
    List result = new ArrayList();
    if(lineString!=null && !lineString.isEmpty()){
      if(delimiter!=null && delimiter.equals(",")){
        List tempList = Util.csvToList(lineString);
        for(String str : tempList){
          if(str == null){
            str = "";
          }
          result.add(str.trim());
        }
      }else{
        String []str = lineString.split(delimiter);
        for(String s : str){
          if(s == null){
            s = "";
          }
          result.add(s.trim());
        }
      }
    }
    return result;
  }

  Set errorListSet = new HashSet();

  List identitiesUpdated = new ArrayList();
  List identitiesNotUpdated = new ArrayList();

  String manager = "manager";
  String contractorManager = "contractorManager";
  String pivotColumn = null;


  String DELIMITER = ",";
  String inputFileName = "";
  boolean isHeader = true;
  String lineString ="";
  FileInputStream inputFile = null;
  Scanner scanner = null;
  List headerList = new ArrayList();
  List dataList = new ArrayList();
  List dateNotInRangeList=new ArrayList();
  List dateFormatErrorList=new ArrayList();
  int ctrExpDtCounter=0;
  boolean isFormatError=false;
  boolean isIncorrectDateRange=false;

  Map feedMap =null;

  try {

    if(config!=null){
      inputFileName = config.get("filePath");
      pivotColumn = config.get("pivotColumn");
    } 

    inputFile = new FileInputStream(inputFileName);

    scanner = new Scanner(inputFile); 
    Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");
    int defaultDays = 0;
    int ctrexpDtMaxDays=Integer.parseInt(custom.get("ctrexpDtMaxDays"));
    while (scanner!=null && scanner.hasNextLine()) {
      lineString = scanner.nextLine();
      if(lineString!=null){
        if(isHeader){
          isHeader = false;
          headerList = delimToList(DELIMITER , lineString);
          continue;
        }
        feedMap = null;
        feedMap = new HashMap();
        int counter = 0;
        for( String col : headerList){
          dataList = delimToList(DELIMITER , lineString);
          if(dataList!=null && dataList.size() == headerList.size()){
          if("ctrexpDt".equalsIgnoreCase(col))
            {
            if(Util.isNullOrEmpty(dataList.get(counter))) {
              defaultDays = Integer.parseInt(custom.get("defaultDays"));
             SimpleDateFormat formatForDefault = new SimpleDateFormat("yyyy-MM-dd");
             Calendar calendar= Calendar.getInstance();
             calendar.add(Calendar.DATE,defaultDays);
             Date dateAfterAddingDefaultDays=calendar.getTime();
             String ctrexpDtToPopulate=formatForDefault.format(dateAfterAddingDefaultDays);
              feedMap.put(col, ctrexpDtToPopulate);
            }
            else{
           String regex= "\\d{4}\\-(0?[1-9]|1[012])\\-(0?[1-9]|[12][0-9]|3[01])*";
            String sdate = dataList.get(counter);
            Pattern pattern = Pattern.compile(regex);
            Matcher matcher = pattern.matcher(sdate);
            boolean matchStatus= matcher.matches();
              if(matchStatus==true && getDifferenceInDays(sdate)>0 && getDifferenceInDays(sdate) <= ctrexpDtMaxDays){
                feedMap.put(col, dataList.get(counter));
              
              }
              else if(matchStatus==true && getDifferenceInDays(sdate)<0 || getDifferenceInDays(sdate) > ctrexpDtMaxDays)
              {
                isIncorrectDateRange=true;
                ++ctrExpDtCounter;
                dateNotInRangeList.add("User Record"+"-"+dataList);
                
              }
               else
               {
                 ++ctrExpDtCounter;
                 dateFormatErrorList.add("User Record"+"-"+dataList);
                 if(matchStatus==false)
                   isFormatError=true;
                 }
          }
            }
            else{
              feedMap.put(col, dataList.get(counter));
            }
          }
          counter++;
        }

        if(feedMap !=null){
          updateIdentity(feedMap);
        }
      }
    }
    context.commitTransaction();
  }catch (FileNotFoundException e) {
    taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
  }catch (GeneralException e) {
    taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));

  }finally{
    if(scanner!=null){
      scanner.close();
    }
    if(inputFile!=null){
      try {
        inputFile.close();
      } catch (IOException e) {
        taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
      }
    }
  }
  
    int totalFailedRecords = 0;
  int totalRecords = 0;
   int updatedRecords = 0;

  taskResult.setAttribute("updateInactive",config.get("updateInactive")); 
  if(identitiesUpdated!=null && !identitiesUpdated.isEmpty()){
    taskResult.setAttribute("updatedNoOfRecords",identitiesUpdated.size());  
    updatedRecords = identitiesUpdated.size();
  taskResult.setAttribute("identitiesUpdated",identitiesUpdated);  
  }
  taskResult.setAttribute("identitiesNotUpdated",identitiesNotUpdated);  
  taskResult.setAttribute("identitiesErrors",errorListSet);
 taskResult.setAttribute("Invalid DOB Format User(s)",dateFormatErrorList);
  if(dateNotInRangeList!=null && !dateNotInRangeList.isEmpty()){
    taskResult.setAttribute("incorrectDateRange#",dateNotInRangeList.size());
    taskResult.setAttribute("incorrectDateRange",dateNotInRangeList);
  }
  if(dateFormatErrorList!=null && !dateFormatErrorList.isEmpty()){
  taskResult.setAttribute("incorrectDateFormat#",dateFormatErrorList.size());
    taskResult.setAttribute("incorrectDateFormat",dateFormatErrorList);
  }

   if(null!=dateFormatErrorList && null!=dateFormatErrorList && errorListSet.size()==0){
      totalFailedRecords = dateNotInRangeList.size()+dateFormatErrorList.size();
  }
  if(errorListSet!=null && errorListSet.size()>0)
  {
    totalFailedRecords=totalFailedRecords+errorListSet.size();
  }
  if(totalFailedRecords>0)
    taskResult.setAttribute("failedNumberOfRecords",totalFailedRecords);
  totalRecords=totalFailedRecords+updatedRecords;
   taskResult.setAttribute("totalRecords",totalRecords); 
  return ""+errorListSet;
